        </div><!-- website_settings_page -->
        <div :class="locale == 'ar' ? ' justify-end' : ' justify-start'" class="mt-2">
            <button type="button" @click="goBack" class="btn bg-gray-600 hover:bg-gray-500 text-white py-2 px-8">{{
                __('Back')
            }}</button>
            <button v-if="enableMyTravel" v-permission = "'sync data to mytravel'" type="button" @click="sync"
                class="btn bg-green-600 hover:bg-green-500 text-white py-2 px-8">{{ __('Sync Data to MyTravel')
                }}</button>
            <button v-if="enableMyTravel" v-permission = "'sync data to mytravel'" type="button" @click="syncImages"
                class="btn bg-green-600 hover:bg-green-500 text-white py-2 px-8">{{ __('Sync Hotel Images to MyTravel')
                }}</button>

    </div>
  </div>
</template>

<script>

export default {
    name: "Website",
    data() {
        return {
            website_domain: null,
            team: Object,
            website: Object,
            installed: false,
            reset: true,
            crumbs: [],
            locale: null,
            MyTravel: 0,
            enableMyTravel: 0,

        }
    },
    mounted() {
        this.crumbs = [
            {
                text: 'Home',
                to: '/dashboards/main',
            },
            {
                text: 'Settings',
                to: '/settings',
            },
            {
                text: 'Website',
                to: '#',
            }
        ]
        this.team = Spark.state.currentTeam;
        this.website_domain = this.team.slug;
        this.MyTravel = this.team.enable_website;
        this.enableMyTravel = this.team.enable_mytravel;

    },
    methods: {
        updateDomain() {
            Nova.request()
                .put("/nova-vendor/settings/update-domain", {
                    id: this.team.id,
                    slug: this.website_domain
                })
                .then(response => {
                    this.team = response.data.team;
                    this.website_domain = this.team.slug;

                        this.$toasted.success(Nova.app.__('Success'), {
                            duration: 3000
                        })
                    })
                    .catch(error => {
                        this.$toasted.error(Nova.app.__('Error'), {
                            duration: 3000
                        });
                    });
            },
            getSettings() {

            },
            goBack() {
                this.$router.push({path: '/settings'})
            },
            sync() {
            let team_id = this.team.id;
                axios.post(window.APP_URL + '/api/link/' + team_id)
                    .then(response => {

                        this.$toasted.show(
                            this.__('Hotel Data Synced Successfully'),
                            { type: 'success' }
                        )

                })
                .catch(error => {
                    if (error.response && error.response.status === 422) {
                        // Display validation errors
                        let errors = error.response.data.errors;

                        for (let field in errors) {
                            if (errors.hasOwnProperty(field)) {
                                this.$toasted.show(
                                    this.__(errors[field][0]), // Show the first error message for each field
                                    { type: 'error' }
                                );
                            }
                        }
                    } else {
                        // Generic error message for other types of errors
                        this.$toasted.show(
                            this.__('Error in Syncing Hotel Data'),
                            { type: 'error' }
                        );
                    }
                });

            },
            syncImages() {
                let team_id = this.team.id;
                axios.post(window.APP_URL + '/api/linkImages/' + team_id)

                    .then(response => {

                        this.$toasted.show(
                            this.__('Hotel Images Synced Successfully'),
                            { type: 'success' }
                        )

                    })
                    .catch(error => {

                        this.$toasted.show(
                            this.__('Error in Syncing Hotel Images'),
                            { type: 'error' }
                        )

                    });
            },
            goTo(type) {
                if (Spark.state.currentTeam.current_billing_plan == 'team-free'){
                    this.$toasted.show(Nova.app.__('Your account on the free plan must be upgraded to reach to manage the website'), { type: 'error' })
                    return;
                }
                this.$router.push({path: type})
            },
        },
        created() {
            if (Spark.state.currentTeam.current_billing_plan == 'team-free'){
                this.$toasted.show(Nova.app.__('Your account on the free plan must be upgraded to reach to manage the website'), { type: 'error' });
                this.goBack();
                return;
            }
            this.locale = Nova.config.local ;
        },
    }
</script>

